async function bindleftCommonSearchdropdown(instance, modulename, filtername) {
    var vm = instance;
    let params = `id=&moduleName=${modulename}&type=${filtername}&search=&refId=`
    await LeadDataService.GetDDLData(params)
        .then(function (response) {
            var json = response.data;
            if (json != null) {

                if (filtername == "LEAD_DEAL_STATUS") {
                    vm.leftSearchFields[3].listOptions = json.DATA;
                    vm.LeadStatusList = json.DATA;
                    return vm.LeadStatusList;
                }
                if (filtername == "LEAD_OWNER_SEARCH") {
                    vm.leftSearchFields[2].listOptions = json.DATA;
                    vm.LeadOwnerList = json.DATA;
                    return vm.LeadOwnerList;
                }
            }
        });
}
export default { buttons, leftsearchSchema, listActions, bindleftCommonSearchdropdown };